  1→import { Bot } from "grammy";
  2→import {
  3→  ChannelAdapter,
  4→  type OpenACPCore,
  5→  type OutgoingMessage,
  6→  type PermissionRequest,
  7→  type NotificationMessage,
  8→  type Session,
  9→  type AgentCommand,
 10→} from "../../core/index.js";
 11→import { createChildLogger } from "../../core/log.js";
 12→const log = createChildLogger({ module: "telegram" });
 13→import type { TelegramChannelConfig } from "./types.js";
 14→import { MessageDraft } from "./streaming.js";
 15→import {
 16→  ensureTopics,
 17→  createSessionTopic,
 18→  renameSessionTopic,
 19→} from "./topics.js";
 20→import {
 21→  setupCommands,
