 40→  formatUsage,
 41→} from "./formatting.js";
 42→
 43→export class TelegramAdapter extends ChannelAdapter {
 44→  private bot!: Bot;
 45→  private telegramConfig: TelegramChannelConfig;
 46→  private sessionDrafts: Map<string, MessageDraft> = new Map();
 47→  private toolCallMessages: Map<
 48→    string,
 49→    Map<string, { msgId: number; name: string; kind?: string }>
 50→  > = new Map(); // sessionId → (toolCallId → state)
 51→  private permissionHandler!: PermissionHandler;
 52→  private assistantSession: Session | null = null;
 53→  private notificationTopicId!: number;
 54→  private assistantTopicId!: number;
 55→  private skillMessages: Map<string, number> = new Map(); // sessionId → pinned messageId
 56→
 57→  constructor(core: OpenACPCore, config: TelegramChannelConfig) {
 58→    super(core, config as any);
 59→    this.telegramConfig = config;
 60→  }
 61→
 62→  async start(): Promise<void> {
 63→    this.bot = new Bot(this.telegramConfig.botToken);
 64→
 65→    // Global error handler — prevent unhandled errors from crashing the bot
 66→    this.bot.catch((err) => {
 67→      log.error({ err: err }, "Telegram bot error");
 68→    });
 69→
 70→    // Ensure allowed_updates includes callback_query on every poll
 71→    this.bot.api.config.use((prev, method, payload, signal) => {
 72→      if (method === "getUpdates") {
 73→        (payload as any).allowed_updates = (payload as any).allowed_updates ?? [
 74→          "message",
 75→          "callback_query",
 76→        ];
 77→      }
 78→      return prev(method, payload, signal);
 79→    });
 80→
 81→    // Register static commands for Telegram autocomplete (scoped to this chat)
 82→    await this.bot.api.setMyCommands(STATIC_COMMANDS, {
 83→      scope: { type: "chat", chat_id: this.telegramConfig.chatId },
 84→    });
 85→
 86→    // Middleware: only accept updates from configured chatId
 87→    this.bot.use((ctx, next) => {
 88→      const chatId = ctx.chat?.id ?? ctx.callbackQuery?.message?.chat?.id;
 89→      if (chatId !== this.telegramConfig.chatId) return;
 90→      return next();
 91→    });
 92→
 93→    // Ensure system topics exist
 94→    const topics = await ensureTopics(
 95→      this.bot,
 96→      this.telegramConfig.chatId,
 97→      this.telegramConfig,
 98→      async (updates) => {
 99→        // Save topic IDs to config
100→        await (this.core as OpenACPCore).configManager.save({
101→          channels: { telegram: updates },
102→        });
103→      },
104→    );
105→    this.notificationTopicId = topics.notificationTopicId;
106→    this.assistantTopicId = topics.assistantTopicId;
107→
108→    // Setup permission handler (instance only, callback registered later)
109→    this.permissionHandler = new PermissionHandler(
110→      this.bot,
111→      this.telegramConfig.chatId,
112→      (sessionId) =>
113→        (this.core as OpenACPCore).sessionManager.getSession(sessionId),
114→      (notification) => this.sendNotification(notification),
115→    );
116→
117→    // Callback registration order matters!
118→    // Specific regex handlers first, catch-all last.
119→    setupSkillCallbacks(this.bot, this.core as OpenACPCore);
120→    setupMenuCallbacks(
121→      this.bot,
122→      this.core as OpenACPCore,
123→      this.telegramConfig.chatId,
124→    );
125→    setupCommands(
126→      this.bot,
127→      this.core as OpenACPCore,
128→      this.telegramConfig.chatId,
129→    );
130→    this.permissionHandler.setupCallbackHandler();
131→
132→    // Setup message routing
133→    this.setupRoutes();
134→
135→    // Start bot polling
136→    this.bot.start({
137→      allowed_updates: ["message", "callback_query"],
138→      onStart: () =>
139→        log.info(
140→          { chatId: this.telegramConfig.chatId },
141→          "Telegram bot started",
142→        ),
143→    });
144→
145→    // Spawn assistant (after bot is started so it can send messages)
146→    try {
147→      this.assistantSession = await spawnAssistant(
148→        this.core as OpenACPCore,
149→        this,
150→        this.assistantTopicId,
151→      );
152→    } catch (err) {
153→      log.error({ err }, "Failed to spawn assistant");
154→    }
155→
156→    // Send welcome message with menu to assistant topic
157→    try {
158→      const config = (this.core as OpenACPCore).configManager.get();
159→      const agents = (
160→        this.core as OpenACPCore
161→      ).agentManager.getAvailableAgents();
162→      const agentList = agents
163→        .map(
164→          (a) =>
165→            `${escapeHtml(a.name)}${a.name === config.defaultAgent ? " (default)" : ""}`,
166→        )
167→        .join(", ");
168→      const workspace = escapeHtml(config.workspace.baseDir);
169→
170→      const welcomeText =
171→        `👋 <b>OpenACP Assistant</b> is online.\n\n` +
172→        `Available agents: ${agentList}\n` +
173→        `Workspace: <code>${workspace}</code>\n\n` +
174→        `<b>Select an action:</b>`;
175→
176→      await this.bot.api.sendMessage(this.telegramConfig.chatId, welcomeText, {
177→        message_thread_id: this.assistantTopicId,
178→        parse_mode: "HTML",
179→        reply_markup: buildMenuKeyboard(),
180→      });
181→    } catch (err) {
182→      log.warn({ err }, "Failed to send welcome message");
183→    }
184→  }
185→
186→  async stop(): Promise<void> {
187→    if (this.assistantSession) {
188→      await this.assistantSession.destroy();
189→    }
190→    await this.bot.stop();
191→    log.info("Telegram bot stopped");
192→  }
193→
194→  private setupRoutes(): void {
195→    this.bot.on("message:text", async (ctx) => {
196→      const threadId = ctx.message.message_thread_id;
197→
198→      // General topic or no thread → redirect to assistant
199→      if (!threadId) {
200→        const html = redirectToAssistant(
201→          this.telegramConfig.chatId,
202→          this.assistantTopicId,
203→        );
204→        await ctx.reply(html, { parse_mode: "HTML" });
205→        return;
206→      }
207→
208→      // Notification topic → ignore
209→      if (threadId === this.notificationTopicId) return;
210→
211→      // Assistant topic → send typing indicator and forward to assistant session
212→      if (threadId === this.assistantTopicId) {
213→        ctx.replyWithChatAction("typing").catch(() => {});
214→        handleAssistantMessage(this.assistantSession, ctx.message.text).catch(
215→          (err) => log.error({ err }, "Assistant error"),
216→        );
217→        return;
218→      }
219→
220→      // Session topic → send typing indicator and forward to core
221→      ctx.replyWithChatAction("typing").catch(() => {});
222→      (this.core as OpenACPCore)
223→        .handleMessage({
224→          channelId: "telegram",
225→          threadId: String(threadId),
226→          userId: String(ctx.from.id),
227→          text: ctx.message.text,
228→        })
229→        .catch((err) => log.error({ err }, "handleMessage error"));
230→    });
231→  }
232→
233→  // --- ChannelAdapter implementations ---
234→
235→  async sendMessage(
236→    sessionId: string,
237→    content: OutgoingMessage,
238→  ): Promise<void> {
239→    log.debug({ sessionId, type: content.type }, "Sending message to Telegram");
240→    const session = (this.core as OpenACPCore).sessionManager.getSession(
241→      sessionId,
242→    );
243→    if (!session) return;
244→    const threadId = Number(session.threadId);
245→
246→    switch (content.type) {
247→      case "thought": {
248→        // Skip thought/thinking content — it's internal agent reasoning
249→        // Users don't need to see it
250→        break;
251→      }
252→
253→      case "text": {
254→        let draft = this.sessionDrafts.get(sessionId);
255→        if (!draft) {
256→          draft = new MessageDraft(
257→            this.bot,
258→            this.telegramConfig.chatId,
259→            threadId,
260→          );
261→          this.sessionDrafts.set(sessionId, draft);
262→        }
263→        draft.append(content.text);
264→        break;
265→      }
266→
267→      case "tool_call": {
268→        await this.finalizeDraft(sessionId);
269→        const meta = content.metadata as any;
270→        const msg = await this.bot.api.sendMessage(
271→          this.telegramConfig.chatId,
272→          formatToolCall(meta),
273→          {
274→            message_thread_id: threadId,
275→            parse_mode: "HTML",
276→            disable_notification: true,
277→          },
278→        );
279→        if (!this.toolCallMessages.has(sessionId)) {
280→          this.toolCallMessages.set(sessionId, new Map());
281→        }
282→        this.toolCallMessages.get(sessionId)!.set(meta.id, {
283→          msgId: msg.message_id,
284→          name: meta.name,
285→          kind: meta.kind,
286→        });
287→        break;
288→      }
289→
290→      case "tool_update": {
291→        const meta = content.metadata as any;
292→        const toolState = this.toolCallMessages.get(sessionId)?.get(meta.id);
293→        if (toolState) {
294→          // Merge name/kind from original tool_call
295→          const merged = {
296→            ...meta,
297→            name: meta.name || toolState.name,
298→            kind: meta.kind || toolState.kind,
299→          };
300→          try {
301→            await this.bot.api.editMessageText(
302→              this.telegramConfig.chatId,
303→              toolState.msgId,
304→              formatToolUpdate(merged),
305→              { parse_mode: "HTML" },
306→            );
307→          } catch {
308→            /* edit failed */
309→          }
310→        }
311→        break;
312→      }
313→
314→      case "plan": {
315→        await this.finalizeDraft(sessionId);
316→        await this.bot.api.sendMessage(
317→          this.telegramConfig.chatId,
318→          formatPlan(content.metadata as any),
319→          {
320→            message_thread_id: threadId,
321→            parse_mode: "HTML",
322→            disable_notification: true,
323→          },
324→        );
325→        break;
326→      }
327→
328→      case "usage": {
329→        // Show usage stats
330→        await this.bot.api.sendMessage(
331→          this.telegramConfig.chatId,
332→          formatUsage(content.metadata as any),
333→          {
334→            message_thread_id: threadId,
335→            parse_mode: "HTML",
336→            disable_notification: true,
337→          },
338→        );
339→        break;
340→      }
341→
342→      case "session_end": {
343→        await this.finalizeDraft(sessionId);
344→        this.sessionDrafts.delete(sessionId);
345→        this.toolCallMessages.delete(sessionId);
346→        await this.cleanupSkillCommands(sessionId);
347→        await this.bot.api.sendMessage(
348→          this.telegramConfig.chatId,
349→          `✅ <b>Done</b>`,
350→          {
351→            message_thread_id: threadId,
352→            parse_mode: "HTML",
353→            disable_notification: true,
354→          },
355→        );
356→        break;
357→      }
358→
359→      case "error": {
360→        await this.finalizeDraft(sessionId);
361→        await this.bot.api.sendMessage(
362→          this.telegramConfig.chatId,
363→          `❌ <b>Error:</b> ${escapeHtml(content.text)}`,
364→          {
365→            message_thread_id: threadId,
366→            parse_mode: "HTML",
367→            disable_notification: true,
368→          },
369→        );
370→        break;
371→      }
372→    }
373→  }
374→
375→  async sendPermissionRequest(
376→    sessionId: string,
377→    request: PermissionRequest,
378→  ): Promise<void> {
379→    log.info({ sessionId, requestId: request.id }, "Permission request sent");
380→    const session = (this.core as OpenACPCore).sessionManager.getSession(
381→      sessionId,
