430→
431→  async sendSkillCommands(sessionId: string, commands: AgentCommand[]): Promise<void> {
432→    const session = (this.core as OpenACPCore).sessionManager.getSession(sessionId);
433→    if (!session) return;
434→    const threadId = Number(session.threadId);
435→    if (!threadId) return;
436→
437→    // Empty commands → remove pinned message
438→    if (commands.length === 0) {
439→      await this.cleanupSkillCommands(sessionId);
440→      return;
441→    }
442→
443→    // Clear old callback entries before building new keyboard
444→    clearSkillCallbacks(sessionId);
445→
446→    const keyboard = buildSkillKeyboard(sessionId, commands);
447→    const text = "🛠 <b>Available commands:</b>";
448→    const existingMsgId = this.skillMessages.get(sessionId);
449→
450→    if (existingMsgId) {
451→      // Update existing pinned message
452→      try {
453→        await this.bot.api.editMessageText(
454→          this.telegramConfig.chatId,
455→          existingMsgId,
456→          text,
457→          { parse_mode: "HTML", reply_markup: keyboard },
458→        );
459→        return;
460→      } catch {
461→        // Message may have been deleted — fall through to create new
462→      }
463→    }
464→
465→    // Create and pin new message
466→    try {
467→      const msg = await this.bot.api.sendMessage(
468→        this.telegramConfig.chatId,
469→        text,
470→        {
471→          message_thread_id: threadId,
472→          parse_mode: "HTML",
473→          reply_markup: keyboard,
474→          disable_notification: true,
475→        },
476→      );
477→      this.skillMessages.set(sessionId, msg.message_id);
478→
479→      await this.bot.api.pinChatMessage(this.telegramConfig.chatId, msg.message_id, {
480→        disable_notification: true,
481→      });
482→    } catch (err) {
483→      log.error({ err, sessionId }, "Failed to send skill commands");
484→    }
485→
486→    // Update Telegram autocomplete with skill commands
487→    await this.updateCommandAutocomplete(commands);
488→  }
489→
490→  async cleanupSkillCommands(sessionId: string): Promise<void> {
491→    const msgId = this.skillMessages.get(sessionId);
492→    if (!msgId) return;
493→
494→    try {
495→      await this.bot.api.editMessageText(
496→        this.telegramConfig.chatId,
497→        msgId,
498→        "🛠 <i>Session ended</i>",
499→        { parse_mode: "HTML" },
500→      );
501→      await this.bot.api.unpinChatMessage(this.telegramConfig.chatId, msgId);
502→    } catch {
503→      /* message may already be deleted */
504→    }
505→
506→    this.skillMessages.delete(sessionId);
507→    clearSkillCallbacks(sessionId);
508→
509→    // Reset autocomplete to static commands only
510→    await this.updateCommandAutocomplete([]);
511→  }
512→
513→  private async updateCommandAutocomplete(skillCommands: AgentCommand[]): Promise<void> {
514→    // Telegram requires: 1-32 chars, lowercase a-z, 0-9, underscores only
515→    const validSkills = skillCommands
516→      .map((c) => ({
517→        command: c.name.toLowerCase().replace(/[^a-z0-9_]/g, "_").slice(0, 32),
518→        description: (c.description || c.name).replace(/\n/g, " ").slice(0, 256),
519→      }))
520→      .filter((c) => c.command.length > 0);
521→    const all = [...STATIC_COMMANDS, ...validSkills];
522→    try {
523→      await this.bot.api.setMyCommands(all, {
524→        scope: { type: "chat", chat_id: this.telegramConfig.chatId },
525→      });
526→      log.info({ count: all.length, skills: validSkills.length }, "Updated command autocomplete");
527→    } catch (err) {
528→      log.error({ err, commands: all }, "Failed to update command autocomplete");
529→    }
530→  }
531→
532→  private async finalizeDraft(sessionId: string): Promise<void> {
533→    const draft = this.sessionDrafts.get(sessionId);
534→    if (draft) {
535→      await draft.finalize();
536→      this.sessionDrafts.delete(sessionId);
537→    }
538→  }
539→}
