  1→import type { Bot } from 'grammy'
  2→import { markdownToTelegramHtml, splitMessage } from './formatting.js'
  3→
  4→export class MessageDraft {
  5→  private messageId?: number
  6→  private buffer: string = ''
  7→  private lastFlush: number = 0
  8→  private flushTimer?: ReturnType<typeof setTimeout>
  9→  private flushPromise: Promise<void> = Promise.resolve()  // serialize flushes
 10→  private minInterval = 1000  // 1 second throttle
 11→
 12→  constructor(
 13→    private bot: Bot,
 14→    private chatId: number,
 15→    private threadId: number,
 16→  ) {}
 17→
 18→  append(text: string): void {
 19→    this.buffer += text
 20→    this.scheduleFlush()
 21→  }
 22→
 23→  private scheduleFlush(): void {
 24→    const now = Date.now()
 25→    const elapsed = now - this.lastFlush
 26→
 27→    if (elapsed >= this.minInterval) {
 28→      // Chain flush to prevent concurrent sends
 29→      this.flushPromise = this.flushPromise.then(() => this.flush()).catch(() => {})
 30→    } else if (!this.flushTimer) {
 31→      this.flushTimer = setTimeout(() => {
 32→        this.flushTimer = undefined
 33→        this.flushPromise = this.flushPromise.then(() => this.flush()).catch(() => {})
 34→      }, this.minInterval - elapsed)
 35→    }
 36→  }
 37→
 38→  private async flush(): Promise<void> {
 39→    if (!this.buffer) return
 40→    this.lastFlush = Date.now()
 41→
 42→    const html = markdownToTelegramHtml(this.buffer)
 43→    // Truncate for streaming (will send full on finalize)
 44→    const truncated = html.length > 4096 ? html.slice(0, 4090) + '\n...' : html
 45→    if (!truncated) return
 46→
 47→    try {
 48→      if (!this.messageId) {
 49→        const msg = await this.bot.api.sendMessage(this.chatId, truncated, {
 50→          message_thread_id: this.threadId,
 51→          parse_mode: 'HTML',
 52→          disable_notification: true,
 53→        })
 54→        this.messageId = msg.message_id
 55→      } else {
 56→        await this.bot.api.editMessageText(this.chatId, this.messageId, truncated, {
 57→          parse_mode: 'HTML',
 58→        })
 59→      }
 60→    } catch {
 61→      // Edit failed — try plain text without HTML parse mode
 62→      try {
 63→        if (!this.messageId) {
 64→          const msg = await this.bot.api.sendMessage(this.chatId, this.buffer.slice(0, 4096), {
 65→            message_thread_id: this.threadId,
 66→            disable_notification: true,
 67→          })
 68→          this.messageId = msg.message_id
 69→        }
 70→      } catch {
 71→        // Give up on this flush
 72→      }
 73→    }
 74→  }
 75→
 76→  async finalize(): Promise<number | undefined> {
 77→    if (this.flushTimer) {
 78→      clearTimeout(this.flushTimer)
 79→      this.flushTimer = undefined
 80→    }
 81→
 82→    // Wait for any in-flight flush to complete
 83→    await this.flushPromise
 84→
 85→    if (!this.buffer) return this.messageId
 86→
 87→    // Final send with full content + splitting
 88→    const html = markdownToTelegramHtml(this.buffer)
 89→    const chunks = splitMessage(html)
 90→
 91→    try {
 92→      for (let i = 0; i < chunks.length; i++) {
 93→        const chunk = chunks[i]
 94→        if (i === 0 && this.messageId) {
 95→          // Edit existing message with first chunk
 96→          await this.bot.api.editMessageText(this.chatId, this.messageId, chunk, {
 97→            parse_mode: 'HTML',
 98→          })
 99→        } else {
100→          // Send new message
101→          const msg = await this.bot.api.sendMessage(this.chatId, chunk, {
102→            message_thread_id: this.threadId,
103→            parse_mode: 'HTML',
104→            disable_notification: true,
105→          })
106→          this.messageId = msg.message_id
107→        }
108→      }
109→    } catch {
110→      // Best effort — try plain text
111→      try {
112→        await this.bot.api.sendMessage(this.chatId, this.buffer.slice(0, 4096), {
113→          message_thread_id: this.threadId,
114→          disable_notification: true,
115→        })
116→      } catch {
117→        // Give up
118→      }
119→    }
120→
121→    return this.messageId
122→  }
123→
124→  getMessageId(): number | undefined {
125→    return this.messageId
126→  }
127→}
