 1→import type { AgentManager } from './agent-manager.js'
 2→import { Session } from './session.js'
 3→
 4→export class SessionManager {
 5→  private sessions: Map<string, Session> = new Map()
 6→
 7→  async createSession(
 8→    channelId: string,
 9→    agentName: string,
10→    workingDirectory: string,
11→    agentManager: AgentManager,
12→  ): Promise<Session> {
13→    const agentInstance = await agentManager.spawn(agentName, workingDirectory)
14→    const session = new Session({ channelId, agentName, workingDirectory, agentInstance })
15→    this.sessions.set(session.id, session)
16→    return session
17→  }
18→
19→  getSession(sessionId: string): Session | undefined {
20→    return this.sessions.get(sessionId)
21→  }
22→
23→  getSessionByThread(channelId: string, threadId: string): Session | undefined {
24→    for (const session of this.sessions.values()) {
25→      if (session.channelId === channelId && session.threadId === threadId) {
26→        return session
27→      }
28→    }
29→    return undefined
30→  }
31→
32→  async cancelSession(sessionId: string): Promise<void> {
33→    const session = this.sessions.get(sessionId)
34→    if (session) await session.cancel()
35→  }
36→
37→  listSessions(channelId?: string): Session[] {
38→    const all = Array.from(this.sessions.values())
39→    if (channelId) return all.filter(s => s.channelId === channelId)
40→    return all
41→  }
42→
43→  async destroyAll(): Promise<void> {
44→    for (const session of this.sessions.values()) {
45→      await session.destroy()
46→    }
47→    this.sessions.clear()
48→  }
49→}
