 1→import type { OpenACPCore, ChannelAdapter, Config, Session } from "../../core/index.js";
 2→
 3→export async function spawnAssistant(
 4→  core: OpenACPCore,
 5→  adapter: ChannelAdapter,
 6→  assistantTopicId: number,
 7→): Promise<Session> {
 8→  const config = core.configManager.get();
 9→
10→  // Create session with default agent
11→  const session = await core.sessionManager.createSession(
12→    "telegram",
13→    config.defaultAgent,
14→    core.configManager.resolveWorkspace(),
15→    core.agentManager,
16→  );
17→  session.threadId = String(assistantTopicId);
18→
19→  // Send system prompt BEFORE wiring events. enqueuePrompt awaits the full
20→  // agent response, so by the time it returns the system prompt conversation
21→  // is complete. Since no event handler is wired yet, the response is
22→  // intentionally discarded — users only see responses to their own messages.
23→  const systemPrompt = buildAssistantSystemPrompt(config);
24→  await session.enqueuePrompt(systemPrompt);
25→
26→  // Wire events to adapter — only messages after this point reach the user
27→  core.wireSessionEvents(session, adapter);
28→
29→  return session;
30→}
31→
32→export function buildAssistantSystemPrompt(config: Config): string {
33→  const agentNames = Object.keys(config.agents).join(", ");
34→  return `You are the OpenACP Assistant. Help users manage their AI coding sessions.
35→
36→Available agents: ${agentNames}
37→Default agent: ${config.defaultAgent}
38→Workspace base: ${config.workspace.baseDir}
39→
