398→    };
399→    let text = `${emoji[notification.type] || "ℹ️"} <b>${escapeHtml(notification.sessionName || notification.sessionId)}</b>\n`;
400→    text += escapeHtml(notification.summary);
401→    if (notification.deepLink) {
402→      text += `\n\n<a href="${notification.deepLink}">→ Go to message</a>`;
403→    }
404→    await this.bot.api.sendMessage(this.telegramConfig.chatId, text, {
405→      message_thread_id: this.notificationTopicId,
