import type { Bot } from 'grammy'
import { InlineKeyboard } from 'grammy'
import { escapeHtml } from './formatting.js'

export interface Step {
  icon: string
  text: string
  detail?: string
  status: 'pending' | 'in_progress' | 'completed' | 'failed'
}

const STATUS_ICON: Record<string, string> = {
  pending: '○',
  in_progress: '◉',
  completed: '✓',
  failed: '✗',
}

/** Map ACP tool names to friendly developer labels */
const TOOL_LABELS: Record<string, string> = {
  Bash: 'Run command',
  Read: 'Read file',
  Write: 'Write file',
  Edit: 'Edit file',
  Glob: 'Search files',
  Grep: 'Search code',
  Agent: 'Run agent',
  WebFetch: 'Fetch URL',
  WebSearch: 'Web search',
  NotebookEdit: 'Edit notebook',
}

/** Map ACP tool names to icons */
const TOOL_ICON: Record<string, string> = {
  Bash: '▶️',
  Read: '📖',
  Write: '📝',
  Edit: '✏️',
  Glob: '🔎',
  Grep: '🔍',
  Agent: '🤖',
  WebFetch: '🌐',
  WebSearch: '🔎',
  NotebookEdit: '📓',
}

const KIND_ICON: Record<string, string> = {
  read: '📖', edit: '✏️', delete: '🗑️', execute: '▶️',
  search: '🔍', fetch: '🌐', think: '🧠', move: '📦', other: '🛠️',
}

export function getToolLabel(name?: string): string {
  if (!name) return 'Tool'
  return TOOL_LABELS[name] || name
}

export function getToolIcon(name?: string, kind?: string): string {
  if (name && TOOL_ICON[name]) return TOOL_ICON[name]
  if (kind && KIND_ICON[kind]) return KIND_ICON[kind]
  return '🛠️'
}

/**
 * Tracks session steps in a single Telegram message that gets edited as steps accumulate.
 * Shows a visual progress tracker with quick action buttons.
 */
export class StepTracker {
  private steps: Step[] = []
  private messageId?: number
  private lastFlush = 0
  private flushTimer?: ReturnType<typeof setTimeout>
  private flushPromise: Promise<void> = Promise.resolve()
  private minInterval = 1000 // 1s throttle
  private sessionId: string

  constructor(
    private bot: Bot,
    private chatId: number,
    private threadId: number,
    sessionId: string,
  ) {
    this.sessionId = sessionId
  }

  addStep(step: Step): number {
    const index = this.steps.length
    this.steps.push(step)
    this.scheduleFlush()
    return index
  }

  updateStep(index: number, update: Partial<Step>): void {
    if (index < 0 || index >= this.steps.length) return
    Object.assign(this.steps[index], update)
    this.scheduleFlush()
  }

  get stepCount(): number {
    return this.steps.length
  }

  private scheduleFlush(): void {
    const now = Date.now()
    const elapsed = now - this.lastFlush

    if (elapsed >= this.minInterval) {
      this.flushPromise = this.flushPromise.then(() => this.flush()).catch(() => {})
    } else if (!this.flushTimer) {
      this.flushTimer = setTimeout(() => {
        this.flushTimer = undefined
        this.flushPromise = this.flushPromise.then(() => this.flush()).catch(() => {})
      }, this.minInterval - elapsed)
    }
  }

  private render(): string {
    const completed = this.steps.filter(s => s.status === 'completed').length
    const total = this.steps.length
    const isDone = this.steps.every(s => s.status === 'completed' || s.status === 'failed')

    // Header with progress
    let header: string
    if (isDone) {
      header = `⚡ <b>${total} step${total !== 1 ? 's' : ''}</b> — done`
    } else {
      header = `⏳ <b>${completed}/${total} steps</b>`
    }

    // Step lines
    const lines = this.steps.map(step => {
      const statusChar = STATUS_ICON[step.status] || '○'
      const isActive = step.status === 'in_progress'
      const isDone = step.status === 'completed'
      const isFailed = step.status === 'failed'

      let line = ''
      if (isDone) {
        line = `  ✅  ${escapeHtml(step.text)}`
      } else if (isFailed) {
        line = `  ❌  ${escapeHtml(step.text)}`
      } else if (isActive) {
        line = `  🔄  <b>${escapeHtml(step.text)}</b>`
      } else {
        line = `  ${statusChar}  ${escapeHtml(step.text)}`
      }

      if (step.detail) {
        const detailText = truncate(step.detail, 120)
        line += `\n        <code>${escapeHtml(detailText)}</code>`
      }
      return line
    })

    return header + '\n\n' + lines.join('\n')
  }

  private buildKeyboard(): InlineKeyboard {
    return new InlineKeyboard()
      .text('⛔ Cancel', `step:cancel:${this.sessionId}`)
      .text('📊 Status', `step:status:${this.sessionId}`)
  }

  private async flush(): Promise<void> {
    if (this.steps.length === 0) return
    this.lastFlush = Date.now()

    const html = this.render()
    const isDone = this.steps.every(s => s.status === 'completed' || s.status === 'failed')

    try {
      if (!this.messageId) {
        const msg = await this.bot.api.sendMessage(this.chatId, html, {
          message_thread_id: this.threadId,
          parse_mode: 'HTML',
          disable_notification: true,
          reply_markup: isDone ? undefined : this.buildKeyboard(),
        })
        this.messageId = msg.message_id
      } else {
        await this.bot.api.editMessageText(this.chatId, this.messageId, html, {
          parse_mode: 'HTML',
          reply_markup: isDone ? undefined : this.buildKeyboard(),
        })
      }
    } catch {
      // Edit failed — ignore (message may be identical or deleted)
    }
  }

  /** Force a final flush */
  async finalize(): Promise<void> {
    if (this.flushTimer) {
      clearTimeout(this.flushTimer)
      this.flushTimer = undefined
    }
    await this.flushPromise
    await this.flush()
  }

  getMessageId(): number | undefined {
    return this.messageId
  }
}

function truncate(text: string, maxLen: number): string {
  if (text.length <= maxLen) return text
  return text.slice(0, maxLen) + '…'
}

